(d) Veri Manipülasyonu
Burada hazırladığın başlangıç kodunu kullanarak veri analizi adımlarını tamamlıyoruz.


library(dslabs)
data("polls_us_election_2016")

my_first &lt;- "Pinar"
my_birth_year &lt;- 1997 

# k sayısını hesapla
k &lt;- (nchar(my_first) + my_birth_year) %% 15 + 8

print(paste("Hesaplanan k değeri:", k))

# ÖDEV KURALI: k kuralına göre ilk veya son satırları göster
if (k %% 2 == 0) {
  print(head(polls_us_election_2016, k))
} else {
  print(tail(polls_us_election_2016, k))
}

# NA (Eksik Veri) Analizi
print(paste("Toplam NA sayısı:", sum(is.na(polls_us_election_2016))))
print("En fazla NA içeren ilk 8 sütun:")
na_counts &lt;- sort(colSums(is.na(polls_us_election_2016)), decreasing = TRUE)
print(head(na_counts, 8))

# NA Değerlerini Değiştirme (Kurala Göre)
new_data &lt;- polls_us_election_2016
for(i in 1:ncol(new_data)) {
  if(is.numeric(new_data[[i]])) {
    new_data[[i]][is.na(new_data[[i]])] &lt;- my_birth_year + k
  } else {
    new_data[[i]] &lt;- as.character(new_data[[i]])
    new_data[[i]][is.na(new_data[[i]])] &lt;- paste0(my_first, "_", k)
  }
}

# Yeni Veri Seti Çıktıları
print("Yeni Veri Seti (k satır):")
if (k %% 2 == 0) {
  print(head(new_data, k))
} else {
  print(tail(new_data, k))
}

print(paste("Yeni veri setinde kalan NA sayısı:", sum(is.na(new_data))))
print(paste("anyNA kontrolü (FALSE olmalı):", anyNA(new_data)))

(d) Veri Manipülasyonu (Kişisel Bilgiler)
Kullanıcı adı “Pinar” ve doğum yılı “1997” bilgilerine göre hesaplamalar yapılmıştır.
#| message: false
library(dslabs)
data("polls_us_election_2016")

# Kişisel Bilgiler
my_first &lt;- "Pinar"
my_birth_year &lt;- 1997

# k Değerinin Hesaplanması
k &lt;- (nchar(my_first) + my_birth_year) %% 15 + 8
cat("Hesaplanan k değeri:", k, "\n")

# k değerine göre ilk veya son satırları göster
if (k %% 2 == 0) {
  cat("\nİlk", k, "satır (k çift):\n")
  print(head(polls_us_election_2016, k))
} else {
  cat("\nSon", k, "satır (k tek):\n")
  print(tail(polls_us_election_2016, k))
}

# NA Değerlerinin Analizi
total_na &lt;- sum(is.na(polls_us_election_2016))
cat("\nToplam NA sayısı:", total_na, "\n")

na_per_col &lt;- sort(colSums(is.na(polls_us_election_2016)), decreasing = TRUE)
cat("\nEn çok NA içeren ilk 8 sütun:\n")
print(head(na_per_col, 8))

# NA Değerlerini Değiştirme
new_data &lt;- polls_us_election_2016

for (i in seq_along(new_data)) {
  if (is.numeric(new_data[[i]])) {
    new_data[[i]][is.na(new_data[[i]])] &lt;- my_birth_year + k
  } else {
    new_data[[i]] &lt;- as.character(new_data[[i]])
    new_data[[i]][is.na(new_data[[i]])] &lt;- paste0(my_first, "_", k)
  }
}

# Yeni Veri Seti Kontrolleri
cat("\nYeni veri setinden k satir:\n")
if (k %% 2 == 0) {
  print(head(new_data, k))
} else {
  print(tail(new_data, k))
}

cat("\nYeni veri setinde kalan NA sayisi:", sum(is.na(new_data)), "\n")
cat("anyNA sonucu (FALSE olmali):", anyNA(new_data), "\n")
